﻿{{/*
Expand the name of the chart.
*/}}
{{- define "webapp.name" -}}
{{- default .Chart.Name .Values.nameOverride | trunc 63 | trimSuffix "-" }}
{{- end }}

{{/*
Create a default fully qualified app name.
We truncate at 63 chars because some Kubernetes name fields are limited to this.
*/}}
{{- define "webapp.fullname" -}}
{{- if .Values.fullnameOverride }}
{{- .Values.fullnameOverride | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- $name := default .Chart.Name .Values.nameOverride }}
{{- if contains $name .Release.Name }}
{{- .Release.Name | trunc 63 | trimSuffix "-" }}
{{- else }}
{{- printf "%s-%s" .Release.Name $name | trunc 63 | trimSuffix "-" }}
{{- end }}
{{- end }}
{{- end }}

{{/*
Create chart name and version as used by the chart label.
*/}}
{{- define "webapp.chart" -}}
{{- printf "%s-%s" .Chart.Name .Chart.Version | replace "+" "_" | trunc 63 | trimSuffix "-" }}
{{- end }}

{{/*
Common labels
*/}}
{{- define "webapp.labels" -}}
helm.sh/chart: {{ include "webapp.chart" . }}
{{ include "webapp.selectorLabels" . }}
{{- if .Chart.AppVersion }}
app.kubernetes.io/version: {{ .Chart.AppVersion | quote }}
{{- end }}
app.kubernetes.io/managed-by: {{ .Release.Service }}
{{- end }}

{{/*
Selector labels
*/}}
{{- define "webapp.selectorLabels" -}}
app.kubernetes.io/name: {{ include "webapp.name" . }}
app.kubernetes.io/instance: {{ .Release.Name }}
{{- end }}

{{/*
Create the name of the service account to use
*/}}
{{- define "webapp.serviceAccountName" -}}
{{- if .Values.serviceAccount }}
{{- if .Values.serviceAccount.create }}
{{- default (include "webapp.fullname" .) .Values.serviceAccount.name }}
{{- else }}
{{- default "default" .Values.serviceAccount.name }}
{{- end }}
{{- else }}
{{- "default" }}
{{- end }}
{{- end }}

﻿apiVersion: apps/v1
kind: Deployment
metadata:
  name: {{ include "webapp.fullname" . }}
  labels:
    {{- include "webapp.labels" . | nindent 4 }}
spec:
  {{- if not .Values.autoscaling.enabled }}
  replicas: {{ .Values.replicaCount }}
  {{- end }}
  selector:
    matchLabels:
      {{- include "webapp.selectorLabels" . | nindent 6 }}
  template:
    metadata:
      labels:
        {{- include "webapp.selectorLabels" . | nindent 8 }}
    spec:
      {{- with .Values.imagePullSecrets }}
      imagePullSecrets:
        {{- toYaml . | nindent 8 }}
      {{- end }}
      securityContext:
        runAsNonRoot: true
        runAsUser: 1000
        fsGroup: 2000
      containers:
        - name: {{ .Chart.Name }}
          image: "{{ .Values.image.repository }}:{{ .Values.image.tag | default .Chart.AppVersion }}"
          imagePullPolicy: {{ .Values.image.pullPolicy }}
          ports:
            - name: http
              containerPort: {{ .Values.service.targetPort }}
              protocol: TCP
          resources:
            {{- toYaml .Values.resources | nindent 12 }}
          securityContext:
            allowPrivilegeEscalation: false
            readOnlyRootFilesystem: true
            capabilities:
              drop: ["ALL"]
          {{- if .Values.probes }}
          livenessProbe:
            httpGet:
              path: {{ .Values.probes.liveness.path }}
              port: http
            initialDelaySeconds: 15
            periodSeconds: 20
          readinessProbe:
            httpGet:
              path: {{ .Values.probes.readiness.path }}
              port: http
            initialDelaySeconds: 5
            periodSeconds: 10
          {{- end }}
          {{- if .Values.env }}
          env:
            {{- range $key, $value := .Values.env }}
            - name: {{ $key }}
              value: {{ $value | quote }}
            {{- end }}
          {{- end }}
          volumeMounts:
            - name: tmp
              mountPath: /tmp
      volumes:
        - name: tmp
          emptyDir: {}

// ============================================================
// TEMPLATE: Pulumi — AWS ECS Fargate Service
// WHEN TO USE: Deploying containers on ECS Fargate with ALB
// PREREQUISITES: AWS account, Pulumi CLI, Node.js
// SECRETS NEEDED: AWS credentials (OIDC recommended)
// WHAT TO CHANGE: config values in Pulumi.<stack>.yaml
// RELATED FILES: cd/pulumi/deploy.yml, terraform/aws-ecs/
// MATURITY: Stable
// ============================================================

import * as pulumi from "@pulumi/pulumi";
import * as aws from "@pulumi/aws";
import * as awsx from "@pulumi/awsx";

const config = new pulumi.Config();
const containerPort = config.getNumber("containerPort") || 3000;  // <-- CHANGE THIS
const cpu = config.getNumber("cpu") || 256;
const memory = config.getNumber("memory") || 512;
const desiredCount = config.getNumber("desiredCount") || 2;
const imageName = config.require("imageName");                    // <-- CHANGE THIS in Pulumi.<stack>.yaml

const project = pulumi.getProject();
const stack = pulumi.getStack();
const prefix = `${project}-${stack}`;

// ── VPC ─────────────────────────────────────────────────────
const vpc = new awsx.ec2.Vpc(`${prefix}-vpc`, {
  numberOfAvailabilityZones: 2,
  natGateways: { strategy: awsx.ec2.NatGatewayStrategy.Single },
  tags: { Project: project, Environment: stack, ManagedBy: "pulumi" },
});

// ── ECS Cluster ─────────────────────────────────────────────
const cluster = new aws.ecs.Cluster(`${prefix}-cluster`, {
  settings: [{ name: "containerInsights", value: "enabled" }],
  tags: { Project: project, Environment: stack, ManagedBy: "pulumi" },
});

// ── Application Load Balancer ───────────────────────────────
const alb = new awsx.lb.ApplicationLoadBalancer(`${prefix}-alb`, {
  subnetIds: vpc.publicSubnetIds,
  tags: { Project: project, Environment: stack, ManagedBy: "pulumi" },
});

// ── ECS Fargate Service ─────────────────────────────────────
const service = new awsx.ecs.FargateService(`${prefix}-svc`, {
  cluster: cluster.arn,
  desiredCount: desiredCount,
  networkConfiguration: {
    subnets: vpc.privateSubnetIds,
    assignPublicIp: false,
  },
  taskDefinitionArgs: {
    container: {
      name: "app",
      image: imageName,
      cpu: cpu,
      memory: memory,
      essential: true,
      portMappings: [{
        containerPort: containerPort,
        targetGroup: alb.defaultTargetGroup,
      }],
      environment: [
        { name: "PORT", value: containerPort.toString() },
      ],
      logConfiguration: {
        logDriver: "awslogs",
        options: {
          "awslogs-group": `/ecs/${prefix}`,
          "awslogs-region": aws.config.region!,
          "awslogs-stream-prefix": "app",
          "awslogs-create-group": "true",
        },
      },
    },
  },
  tags: { Project: project, Environment: stack, ManagedBy: "pulumi" },
});

// ── Outputs ─────────────────────────────────────────────────
export const clusterName = cluster.name;
export const serviceArn = service.service.id;
export const albDnsName = alb.loadBalancer.dnsName;
export const url = pulumi.interpolate`http://${alb.loadBalancer.dnsName}`;
export const vpcId = vpc.vpcId;

// ============================================================
// TEMPLATE: Pulumi — Azure AKS Cluster
// WHEN TO USE: Provisioning AKS with ACR integration
// PREREQUISITES: Azure subscription, Pulumi CLI, Node.js
// SECRETS NEEDED: Azure credentials (OIDC recommended)
// WHAT TO CHANGE: config values in Pulumi.<stack>.yaml
// RELATED FILES: cd/pulumi/deploy.yml, terraform/azure-aks/
// MATURITY: Stable
// ============================================================

import * as pulumi from "@pulumi/pulumi";
import * as azure from "@pulumi/azure-native";

const config = new pulumi.Config();
const nodeCount = config.getNumber("nodeCount") || 3;
const nodeVmSize = config.get("nodeVmSize") || "Standard_D2s_v3";
const kubernetesVersion = config.get("kubernetesVersion") || "1.29";

const project = pulumi.getProject();
const stack = pulumi.getStack();
const prefix = `${project}-${stack}`;

// ── Resource Group ──────────────────────────────────────────
const resourceGroup = new azure.resources.ResourceGroup(`${prefix}-rg`, {
  tags: { Project: project, Environment: stack, ManagedBy: "pulumi" },
});

// ── Container Registry ─────────────────────────────────────
const acr = new azure.containerregistry.Registry(`${prefix}acr`.replace(/-/g, ""), {
  resourceGroupName: resourceGroup.name,
  sku: { name: azure.containerregistry.SkuName.Basic },          // <-- CHANGE THIS: Standard or Premium for prod
  adminUserEnabled: false,
  tags: { Project: project, Environment: stack, ManagedBy: "pulumi" },
});

// ── AKS Cluster ─────────────────────────────────────────────
const cluster = new azure.containerservice.ManagedCluster(`${prefix}-aks`, {
  resourceGroupName: resourceGroup.name,
  kubernetesVersion: kubernetesVersion,
  dnsPrefix: prefix,
  identity: { type: azure.containerservice.ResourceIdentityType.SystemAssigned },
  agentPoolProfiles: [{
    name: "system",
    count: nodeCount,
    vmSize: nodeVmSize,
    osType: azure.containerservice.OSType.Linux,
    mode: azure.containerservice.AgentPoolMode.System,
    enableAutoScaling: true,
    minCount: 1,
    maxCount: nodeCount * 2,
  }],
  networkProfile: {
    networkPlugin: "azure",
    networkPolicy: "calico",
    serviceCidr: "10.0.0.0/16",
    dnsServiceIP: "10.0.0.10",
  },
  addonProfiles: {
    omsagent: {
      enabled: true,
      config: {},                                                  // <-- CHANGE THIS: add logAnalyticsWorkspaceResourceID
    },
  },
  tags: { Project: project, Environment: stack, ManagedBy: "pulumi" },
});

// ── ACR Pull Role Assignment ────────────────────────────────
const acrPull = new azure.authorization.RoleAssignment(`${prefix}-acr-pull`, {
  principalId: cluster.identityProfile.apply(p => p!["kubeletidentity"].objectId!),
  principalType: azure.authorization.PrincipalType.ServicePrincipal,
  roleDefinitionId: "/providers/Microsoft.Authorization/roleDefinitions/7f951dda-4ed3-4680-a7ca-43fe172d538d", // AcrPull
  scope: acr.id,
});

// ── Outputs ─────────────────────────────────────────────────
export const clusterName = cluster.name;
export const resourceGroupName = resourceGroup.name;
export const acrLoginServer = acr.loginServer;
export const kubeconfig = pulumi
  .all([resourceGroup.name, cluster.name])
  .apply(([rgName, clusterName]) =>
    azure.containerservice.listManagedClusterUserCredentials({
      resourceGroupName: rgName,
      resourceName: clusterName,
    }),
  )
  .apply(creds => {
    const encoded = creds.kubeconfigs[0].value;
    return Buffer.from(encoded, "base64").toString("utf-8");
  });

// ============================================================
// TEMPLATE: Pulumi — GCP GKE Autopilot Cluster
// WHEN TO USE: Provisioning GKE Autopilot with Artifact Registry
// PREREQUISITES: GCP project, Pulumi CLI, Node.js
// SECRETS NEEDED: GCP credentials (Workload Identity Federation recommended)
// WHAT TO CHANGE: config values in Pulumi.<stack>.yaml
// RELATED FILES: cd/pulumi/deploy.yml, terraform/gcp-gke/
// MATURITY: Stable
// ============================================================

import * as pulumi from "@pulumi/pulumi";
import * as gcp from "@pulumi/gcp";

const config = new pulumi.Config();
const machineType = config.get("machineType") || "e2-medium";
const nodeCount = config.getNumber("nodeCount") || 3;

const project = pulumi.getProject();
const stack = pulumi.getStack();
const prefix = `${project}-${stack}`;

// ── Enable required APIs ────────────────────────────────────
const apis = [
  "container.googleapis.com",
  "artifactregistry.googleapis.com",
  "compute.googleapis.com",
];

const enabledApis = apis.map(
  (api) => new gcp.projects.Service(`${prefix}-${api}`, {
    service: api,
    disableOnDestroy: false,
  }),
);

// ── VPC Network ─────────────────────────────────────────────
const network = new gcp.compute.Network(`${prefix}-vpc`, {
  autoCreateSubnetworks: false,
}, { dependsOn: enabledApis });

const subnet = new gcp.compute.Subnetwork(`${prefix}-subnet`, {
  network: network.id,
  ipCidrRange: "10.0.0.0/20",
  secondaryIpRanges: [
    { rangeName: "pods", ipCidrRange: "10.4.0.0/14" },
    { rangeName: "services", ipCidrRange: "10.8.0.0/20" },
  ],
});

// ── GKE Cluster ─────────────────────────────────────────────
const cluster = new gcp.container.Cluster(`${prefix}-gke`, {
  network: network.id,
  subnetwork: subnet.id,
  location: gcp.config.region!,
  removeDefaultNodePool: true,
  initialNodeCount: 1,
  ipAllocationPolicy: {
    clusterSecondaryRangeName: "pods",
    servicesSecondaryRangeName: "services",
  },
  workloadIdentityConfig: {
    workloadPool: `${gcp.config.project}.svc.id.goog`,
  },
  releaseChannel: { channel: "REGULAR" },
  resourceLabels: {
    project: project,
    environment: stack,
    "managed-by": "pulumi",
  },
}, { dependsOn: enabledApis });

// ── Node Pool ───────────────────────────────────────────────
const nodePool = new gcp.container.NodePool(`${prefix}-pool`, {
  cluster: cluster.name,
  location: gcp.config.region!,
  nodeCount: nodeCount,
  autoscaling: {
    minNodeCount: 1,
    maxNodeCount: nodeCount * 2,
  },
  nodeConfig: {
    machineType: machineType,
    oauthScopes: ["https://www.googleapis.com/auth/cloud-platform"],
    workloadMetadataConfig: {
      mode: "GKE_METADATA",
    },
    shieldedInstanceConfig: {
      enableSecureBoot: true,
      enableIntegrityMonitoring: true,
    },
  },
  management: {
    autoRepair: true,
    autoUpgrade: true,
  },
});

// ── Artifact Registry ───────────────────────────────────────
const registry = new gcp.artifactregistry.Repository(`${prefix}-repo`, {
  format: "DOCKER",
  location: gcp.config.region!,
  description: `Container images for ${prefix}`,
  labels: { project: project, environment: stack, "managed-by": "pulumi" },
}, { dependsOn: enabledApis });

// ── Outputs ─────────────────────────────────────────────────
export const clusterName = cluster.name;
export const clusterEndpoint = cluster.endpoint;
export const registryUrl = pulumi.interpolate`${registry.location}-docker.pkg.dev/${gcp.config.project}/${registry.repositoryId}`;
export const kubeconfig = pulumi.interpolate`
apiVersion: v1
kind: Config
clusters:
- cluster:
    server: https://${cluster.endpoint}
    certificate-authority-data: ${cluster.masterAuth.clusterCaCertificate}
  name: ${cluster.name}
contexts:
- context:
    cluster: ${cluster.name}
    user: ${cluster.name}
  name: ${cluster.name}
current-context: ${cluster.name}
users:
- name: ${cluster.name}
  user:
    exec:
      apiVersion: client.authentication.k8s.io/v1beta1
      command: gke-gcloud-auth-plugin
      installHint: Install gke-gcloud-auth-plugin for kubectl
`;

﻿// vars/buildAndTest.groovy
// Jenkins Shared Library — call as: buildAndTest(tech: 'dotnet')

def call(Map config = [:]) {
    def tech = config.tech ?: 'node'

    pipeline {
        agent any

        stages {
            stage('Build & Test') {
                steps {
                    script {
                        if (tech == 'dotnet') {
                            sh 'dotnet build && dotnet test'
                        } else if (tech == 'python') {
                            sh 'pip install -r requirements.txt && pytest'
                        } else if (tech == 'node') {
                            sh 'npm ci && npm test'
                        }
                    }
                }
            }
        }
    }
}

﻿// ============================================================
// TEMPLATE: Jenkins — .NET Declarative Pipeline
// WHEN TO USE: .NET projects using Jenkins for CI/CD
// PREREQUISITES: Docker agent with .NET SDK image, Slack plugin
// SECRETS NEEDED: registry-credentials (Jenkins credential ID)
// WHAT TO CHANGE: Lines marked with // <-- CHANGE THIS
// RELATED FILES: docker/dotnet/Dockerfile.api
// MATURITY: Stable
// ============================================================

// Jenkins Declarative Pipeline — .NET Build & Test
pipeline {
    agent {
        docker {
            image 'mcr.microsoft.com/dotnet/sdk:8.0'
            args '-v $HOME/.nuget:/root/.nuget'
        }
    }

    options {
        timeout(time: 30, unit: 'MINUTES')
        buildDiscarder(logRotator(numToKeepStr: '10'))
    }

    stages {
        stage('Restore') {
            steps {
                sh 'dotnet restore'
            }
        }

        stage('Build') {
            steps {
                sh 'dotnet build --no-restore --configuration Release'
            }
        }

        stage('Test') {
            steps {
                sh '''
                    dotnet test --no-build --configuration Release \
                        --logger "trx;LogFileName=TestResults.trx" \
                        --collect:"XPlat Code Coverage"
                '''
            }
            post {
                always {
                    mstest testResultsFile: '**/TestResults.trx', keepLongStdio: true
                }
            }
        }

        stage('Docker Build') {
            when { branch 'main' }
            steps {
                script {
                    def image = docker.build("${env.IMAGE_NAME}:${env.BUILD_NUMBER}",
                        '-f docker/dotnet/Dockerfile.api .')
                    docker.withRegistry("https://${env.REGISTRY}", 'registry-credentials') {
                        image.push()
                        image.push('latest')
                    }
                }
            }
        }
    }

    post {
        failure {
            slackSend(channel: '#ci-alerts', color: 'danger',
                message: "Build FAILED: ${env.JOB_NAME} #${env.BUILD_NUMBER}")
        }
        success {
            slackSend(channel: '#ci-alerts', color: 'good',
                message: "Build PASSED: ${env.JOB_NAME} #${env.BUILD_NUMBER}")
        }
    }
}

﻿// ============================================================
// TEMPLATE: Jenkins — Python Declarative Pipeline
// WHEN TO USE: Python projects using Jenkins for CI/CD
// PREREQUISITES: Docker agent with Python image, junit + coverage plugins
// SECRETS NEEDED: None for CI
// WHAT TO CHANGE: Lines marked with // <-- CHANGE THIS
// RELATED FILES: quality/python/pyproject.toml
// MATURITY: Stable
// ============================================================

// Jenkins Declarative Pipeline — Python Build & Test
pipeline {
    agent {
        docker {
            image 'python:3.12-slim'
            args '-v $HOME/.cache/pip:/root/.cache/pip'
        }
    }

    options {
        timeout(time: 20, unit: 'MINUTES')
        buildDiscarder(logRotator(numToKeepStr: '10'))
    }

    stages {
        stage('Install') {
            steps {
                sh 'pip install -r requirements.txt -r requirements-dev.txt'
            }
        }

        stage('Lint') {
            steps {
                sh 'ruff check .'
                sh 'black --check .'
            }
        }

        stage('Test') {
            steps {
                sh 'pytest --junitxml=test-results.xml --cov=. --cov-report=xml'
            }
            post {
                always {
                    junit 'test-results.xml'
                    publishCoverage adapters: [coberturaAdapter('coverage.xml')]
                }
            }
        }
    }

    post {
        failure {
            slackSend(channel: '#ci-alerts', color: 'danger',
                message: "Python build FAILED: ${env.JOB_NAME} #${env.BUILD_NUMBER}")
        }
    }
}

﻿server {
    listen 80;
    server_name _;
    root /usr/share/nginx/html;
    index index.html;

    # Gzip compression
    gzip on;
    gzip_min_length 256;
    gzip_types text/plain text/css application/json application/javascript text/xml application/xml text/javascript image/svg+xml;

    # Angular routing — fallback to index.html for client-side routes
    location / {
        try_files $uri $uri/ /index.html;
    }

    # Cache static assets aggressively (Angular hashes filenames)
    location ~* \.(js|css|png|jpg|jpeg|gif|ico|svg|woff|woff2|ttf|eot)$ {
        expires 1y;
        add_header Cache-Control "public, immutable";
    }

    # Security headers
    add_header X-Frame-Options "SAMEORIGIN";
    add_header X-Content-Type-Options "nosniff";
    add_header X-XSS-Protection "0";
    add_header Referrer-Policy "strict-origin-when-cross-origin";
}

